#include<bits/stdc++.h>
using namespace std;
int dp[131072],f[21][100010],a[100010],b[21],n,k;
int main()
{
    scanf("%d%d",&k,&n);
    for(int i=1;i<=k;i++)
    {
        scanf("%d",&b[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=k;i++)
    {
        int sum=0,r=1;
        for(int l=1;l<=n;l++)
        {
            while(r<=n&&sum+a[r]<=b[i])
            {
                sum+=a[r];
                r++;
            }
            f[i][l]=r-1;
            if(sum)
            {
                sum-=a[l];
            }
        }
    }
    for(int i=0;i<(1<<k);i++)
    {
        for(int j=1;j<=k;j++)
        {
            if(!(i&(1<<(j-1))))
            {
                if(dp[i]>=n)
                {
                    continue;
                }
                dp[i|(1<<(j-1))]=max(dp[i|(1<<(j-1))],f[j][dp[i]+1]);
            }
        }
    }
    int ans=-1;
    for(int i=0;i<(1<<k);i++)
    {
        if(dp[i]<n)
        {
            continue;
        }
        int sum=0;
        for(int j=1;j<=k;j++)
        {
            if(!(i&(1<<(j-1))))
            {
                sum+=b[j];
            }
        }
        ans=max(ans,sum);
    }
    printf("%d",ans);
    return 0;
}
